    {9292,"Cracked Necrotic Crystal",60,-368,{"wago","emulator"},"On the corpse of the fallen abomination, you discover a cracked crystal, slowly pulsing with necrotic energy.",nil,{16431},nil,60,0,nil,"Bring the Cracked Necrotic Crystal to Lieutenant Orrin outside the gates of Stormwind.",0,nil,77,nil,{16478}},
    {9295,"Letter from the Front",60,-368,{"wago","emulator"},"You found this letter on one of the many Scourge minions you've slain. From its appearance and smell, it has been with the undead for some time. Perhaps someone at Light's Hope Chapel would be interested in examining it further...",nil,nil,nil,55,0,nil,"Take the Torn Letter to the Keeper of the Rolls at Light's Hope Chapel in the Eastern Plaguelands.",0,nil,nil,nil,{16281}},
    {9299,"Note from the Front",60,-368,{"wago","emulator"},"You found this letter on one of the many Scourge minions you've slain. From its appearance and smell, it has been with the undead for some time. Perhaps someone at Light's Hope Chapel would be interested in examining it further...",nil,nil,nil,55,0,nil,"Take the Careworn Note to the Keeper of the Rolls at Light's Hope Chapel in the Eastern Plaguelands.",0,nil,nil,nil,{16281}},
    {9300,"Page from the Front",60,-368,{"wago","emulator"},"You found this letter on one of the many Scourge minions you've slain. From its appearance and smell, it has been with the undead for some time. Perhaps someone at Light's Hope Chapel would be interested in examining it further...",nil,nil,nil,55,0,nil,"Take the Ragged Page to the Keeper of the Rolls at Light's Hope Chapel in the Eastern Plaguelands.",0,nil,nil,nil,{16281}},
    {9301,"Envelope from the Front",60,-368,{"wago","emulator"},"You found this letter on one of the many Scourge minions you've slain. From its appearance and smell, it has been with the undead for some time. Perhaps someone at Light's Hope Chapel would be interested in examining it further...",nil,nil,nil,55,0,nil,"Take the Bloodstained Envelope to the Keeper of the Rolls at Light's Hope Chapel in the Eastern Plaguelands.",0,nil,nil,nil,{16281}},
    {9302,"Missive from the Front",60,-368,{"wago","emulator"},"You found this letter on one of the many Scourge minions you've slain. From its appearance and smell, it has been with the undead for some time. Perhaps someone at Light's Hope Chapel would be interested in examining it further...",nil,nil,nil,55,0,nil,"Take the Crumpled Missive to the Keeper of the Rolls at Light's Hope Chapel in the Eastern Plaguelands.",0,nil,nil,nil,{16281}},
    {9304,"Document from the Front",60,-368,{"wago","emulator"},"You found this letter on one of the many Scourge minions you've slain. From its appearance and smell, it has been with the undead for some time. Perhaps someone at Light's Hope Chapel would be interested in examining it further...",nil,nil,nil,55,0,nil,"Take the Smudged Document to the Keeper of the Rolls at Light's Hope Chapel in the Eastern Plaguelands.",0,nil,nil,nil,{16281}},
    {9310,"Faint Necrotic Crystal",60,-368,{"wago","emulator"},"On the corpse of the fallen wight, you find a crystal that is faintly radiating necrotic energy.",nil,{16531},nil,60,0,nil,"Bring the Faint Necrotic Crystal to Lieutenant Rukag in the courtyard of the Undercity.",0,nil,178,nil,{16494}},
    {9317,"Consecrated Sharpening Stones",60,-368,{"emulator"},nil,nil,{16786},{{itemID=23122,count=1}},58,0,nil,nil,8,nil,1101,nil,{16786}},
    {9318,"Blessed Wizard Oil",0,-368,{"emulator"},nil,nil,{16786},{{itemID=23123,count=1}},50,0,nil,nil,8,nil,1101,nil,{16786}},
    {9319,"A Light in Dark Places",60,-369,{"wago","emulator"},"We are not the only ones who celebrate this holiday, $n. All creatures, all cultures, are touched by the flame. Even in the darkest places, the fires are being lit.$B$BIf you wish to see them for yourself, travel into the depths. Seek out the bonfires burning within Stratholme, Scholomance, among the ogres of Dire Maul, and the halls of Blackrock Spire itself; I will await your return.",nil,{16788},{{itemID=23083,count=1},{itemID=23247,count=10}},50,0,{"Flame of Dire Maul","Flame of Blackrock Spire","Flame of Stratholme","Flame of the Scholomance"},"Find and touch the bonfires located within Blackrock Spire, Dire Maul, Scholomance, and Stratholme, then return to the Festival Flamekeeper.",8,nil,77,nil,{16788}},
    {9320,"Major Mana Potion",60,-368,{"emulator"},nil,nil,{16787},{{itemID=13444,count=1}},55,0,nil,nil,8,nil,690,nil,{16787}},
    {9321,"Major Healing Potion",-1,0,{"emulator"},nil,nil,{16786},{{itemID=13446,count=1}},50,0,nil,nil,8,nil,1101,nil,{16786}},
    {9322,"Wild Fires in Kalimdor",60,-369,{"wago","emulator"},"The Midsummer Fire Festival is celebrated everywhere in Azeroth, and the diverse land of Kalimdor is no exception. You look fit to travel -- perhaps a journey is in order.$B$BMidsummer cannot be truly appreciated unless you've seen the blistering blue fires abroad. The celebrants have lit fires in chilly western Winterspring, northeastern Azshara, near Valor's Rest in the wastes of Silithus, and by the entrance to lush Un'Goro. Return once your journey is complete.",nil,{16788},{{itemID=23379,count=1},{itemID=23247,count=10}},50,0,nil,"Visit the Midsummer camps located in Azshara, Silithus, Un'Goro Crater, and Winterspring, then return to the Festival Flamekeeper.",8,nil,nil,nil,{16788}},
    {9323,"Wild Fires in the Eastern Kingdoms",60,-369,{"wago","emulator"},"Our celebration of the flame is spread throughout the land, $c. Not a single place remains untouched by the heat of this holiday, and the strongest fires burn a brilliant blue. Seek them out.$B$BYou'll find one just north of Blackrock Spire. The others are located deep within the Eastern Plaguelands near a decrepit town, along the road to the cliffs within the mountainous Hinterlands, and on the way to the Dark Portal within the Blasted Lands.$B$B Return once your journey is done.",nil,{16788},{{itemID=23324,count=1},{itemID=23247,count=10}},50,0,nil,"Visit the Fire Festival camps located in Blasted Lands, Eastern Plaguelands, the Hinterlands and Searing Gorge, then speak with the Festival Flamekeeper.",8,nil,nil,nil,{16788}},
    {9324,"Stealing Orgrimmar's Flame",60,-369,{"wago","emulator"},"This flame, stolen from the heart of Orgrimmar itself, floods you with warmth. This raw power is foreign to you, but the Loremaster might know more...",nil,nil,{{itemID=23247,count=25}},50,0,nil,"Return the Flame of Orgrimmar to the Festival Loremaster.",0,nil,77,nil,{16817}},
    {9325,"Stealing Thunder Bluff's Flame",60,-369,{"wago","emulator"},"This flame, stolen from the shaman of Thunder Bluff, floods you with warmth. This raw power is foreign to you, but the Loremaster might know more...",nil,nil,{{itemID=23247,count=25}},50,0,nil,"Return the Flame of Thunder Bluff to the Festival Loremaster.",0,nil,77,nil,{16817}},
    {9326,"Stealing the Undercity's Flame",60,-369,{"wago","emulator"},"This flame, stolen from the ruins above the Undercity, floods you with warmth. This raw power is foreign to you, but the Loremaster might know more...",nil,nil,{{itemID=23247,count=25}},50,0,nil,"Return the Flame of the Undercity to the Festival Loremaster.",0,nil,77,nil,{16817}},
    {9330,"Stealing Stormwind's Flame",60,-369,{"wago","emulator"},"This flame, stolen from the heart of Stormwind itself, floods you with warmth. This raw power is foreign to you, but the Talespinner might know more...",nil,nil,{{itemID=23247,count=25}},50,0,nil,"Return the Flame of Stormwind to the Festival Talespinner.",0,nil,178,nil,{16818}},
    {9331,"Stealing Ironforge's Flame",60,-369,{"wago","emulator"},"This flame, stolen from the heart of Ironforge itself, floods you with warmth. This raw power is foreign to you, but the Talespinner might know more...",nil,nil,{{itemID=23247,count=25}},50,0,nil,"Return the Flame of Ironforge to the Festival Talespinner.",0,nil,178,nil,{16818}},
    {9332,"Stealing Darnassus's Flame",60,-369,{"wago","emulator"},"This flame, stolen from the shores of Teldrassil, floods you with warmth. This raw power is foreign to you, but the Talespinner might know more...",nil,nil,{{itemID=23247,count=25}},50,0,nil,"Return the Flame of Darnassus to the Festival Talespinner.",0,nil,178,nil,{16818}},
    {9333,"Argent Dawn Gloves",60,-368,{"emulator"},nil,nil,{16787},nil,55,0,nil,nil,8,nil,690,nil,{16787}},
